import sys

def solve():
    data = sys.stdin.read().split()
    if not data:
        print(0)
        return
    H = int(data[0])
    W = int(data[1])
    K = int(data[2])
    grid = data[3:3+H]

    empty_cells = []
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                empty_cells.append((i, j))

    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    total_paths = 0

    for start_i, start_j in empty_cells:
        start_mask = 1 << (start_i * W + start_j)
        stack = [(start_i, start_j, start_mask, 0)]

        while stack:
            i, j, visited, steps = stack.pop()
            if steps == K:
                total_paths += 1
                continue

            for di, dj in directions:
                ni, nj = i + di, j + dj
                if 0 <= ni < H and 0 <= nj < W and grid[ni][nj] == '.':
                    bit = 1 << (ni * W + nj)
                    if not (visited & bit):
                        stack.append((ni, nj, visited | bit, steps + 1))

    print(total_paths)

if __name__ == "__main__":
    solve()
